1	// Playwright smoke test for ddx-9ce6842a AC §8.
2	//
3	// These tests measure wall-clock time from page.goto to "list is
4	// interactive" against a mocked GraphQL layer that returns a realistic-
5	// sized payload (50 beads — the default page window). They are ceilings,
6	// not p95 targets: the gate catches outright regressions (runaway render
7	// loops, missing virtualization, blocking scripts) without tying the
8	// repo's green/red status to machine speed.
9	//
10	// The matching server-side ceilings (GraphQL response under the same
11	// budget on the real fixture) are enforced in
12	// cli/internal/server/perf/smoke_test.go — together they guard the full
13	// round-trip the user feels.
14	import { expect, test } from '@playwright/test';
15	
16	// Resolve the harness-derived fixture node + project IDs at runtime by
17	// querying GraphQL nodeInfo and /api/projects. The fixture harness boots
18	// ddx-server from a `mktemp -d -t ddx-e2e-XXXXXX` workspace, so the fixture
19	// project's path is prefixed with `ddx-e2e-`. Other entries in /api/projects
20	// (carried over in the developer's persisted server state) must not be picked
21	// up here — those would point the spec at unrelated, developer-local data.
22	async function getFixtureIds(
23		request: import('@playwright/test').APIRequestContext
24	): Promise<{ nodeId: string; projectId: string; nodeName: string; projectName: string; projectPath: string }> {
25		const nodeResp = await request.post('/graphql', {
26			data: { query: '{ nodeInfo { id name } }' }
27		});
28		const nodeBody = (await nodeResp.json()) as {
29			data: { nodeInfo: { id: string; name: string } };
30		};
31		const projectsResp = await request.get('/api/projects');
32		const projects = (await projectsResp.json()) as Array<{ id: string; name: string; path: string }>;
33		const fixture = projects.find((p) => /(^|\/)ddx-e2e-/.test(p.path) || /^ddx-e2e-/.test(p.name));
34		if (!fixture) {
35			throw new Error(
36				`fixture server has no ddx-e2e-* project registered (got: ${projects
37					.map((p) => p.id)
38					.join(', ')})`
39			);
40		}
41		return {
42			nodeId: nodeBody.data.nodeInfo.id,
43			projectId: fixture.id,
44			nodeName: nodeBody.data.nodeInfo.name,
45			projectName: fixture.name,
46			projectPath: fixture.path
47		};
48	}
49	
50	function generateBeads(count: number) {
51		const beads = [];
52		for (let i = 0; i < count; i++) {
53			beads.push({
54				id: `ddx-smoke-${String(i).padStart(4, '0')}`,
55				title: `Smoke fixture bead ${i}`,
56				status: i % 3 === 0 ? 'closed' : 'open',
57				priority: i % 4,
58				labels: ['smoke', `bucket-${i % 7}`]
59			});
60		}
61		return beads;
62	}
63	
64	async function mockSmokeGraphQL(
65		page: import('@playwright/test').Page,
66		beadCount: number,
67		ids: { nodeId: string; projectId: string; nodeName: string; projectName: string; projectPath: string }
68	) {
69		const beads = generateBeads(beadCount);
70		const nodeInfo = { id: ids.nodeId, name: ids.nodeName };
71		const projects = [{ id: ids.projectId, name: ids.projectName, path: ids.projectPath }];
72		await page.route('/graphql', async (route) => {
73			const body = route.request().postDataJSON() as { query: string };
74			if (body.query.includes('beadsByProject')) {
75				await route.fulfill({
76					status: 200,
77					contentType: 'application/json',
78					body: JSON.stringify({
79						data: {
80							beadsByProject: {
81								edges: beads.map((b, i) => ({ node: b, cursor: `cursor-${i}` })),
82								pageInfo: { hasNextPage: false, endCursor: null },
83								totalCount: beads.length
84							}
85						}
86					})
87				});
88			} else if (body.query.includes('beads(')) {
89				// Cross-project list fetches the `beads` field.
90				await route.fulfill({
91					status: 200,
92					contentType: 'application/json',
93					body: JSON.stringify({
94						data: {
95							beads: {
96								edges: beads.map((b, i) => ({ node: b, cursor: `cursor-${i}` })),
97								pageInfo: { hasNextPage: false, endCursor: null },
98								totalCount: beads.length
99							},
100							projects: { edges: projects.map((p) => ({ node: p })) }
101						}
102					})
103				});
104			} else if (body.query.includes('nodeInfo')) {
105				await route.fulfill({
106					status: 200,
107					contentType: 'application/json',
108					body: JSON.stringify({ data: { nodeInfo } })
109				});
110			} else if (body.query.includes('projects')) {
111				await route.fulfill({
112					status: 200,
113					contentType: 'application/json',
114					body: JSON.stringify({
115						data: { projects: { edges: projects.map((p) => ({ node: p })) } }
116					})
117				});
118			} else {
119				await route.continue();
120			}
121		});
122	}
