124	// ddx-9ce6842a AC §8: per-project /beads interactive within 1s.
125	test('smoke: /beads list is interactive within 1s on 50-bead fixture', async ({ page, request }) => {
126		const ids = await getFixtureIds(request);
127		await mockSmokeGraphQL(page, 50, ids);
128	
129		const start = Date.now();
130		await page.goto(`/nodes/${ids.nodeId}/projects/${ids.projectId}/beads`);
131		// "Interactive" = the heading has rendered AND at least one bead row is
132		// visible (so clicking it would navigate). Both are prerequisites to a
133		// real user clicking anything.
134		await expect(page.getByRole('heading', { name: 'Beads' })).toBeVisible({ timeout: 1000 });
135		await expect(page.getByText('Smoke fixture bead 0')).toBeVisible({ timeout: 1000 });
136		const elapsed = Date.now() - start;
137		expect(elapsed, `per-project /beads interactive in ${elapsed}ms (ceiling 1000ms)`).toBeLessThan(
138			1000
139		);
140	});
141	
142	// ddx-9ce6842a AC §8: cross-project /beads interactive within 2s.
143	// We drive the same list view with 300 rows to mimic the cross-project
144	// aggregate load — the backend ceiling is wider (2s) because the real call
145	// is beads() with no projectID.
146	test('smoke: cross-project /beads list is interactive within 2s on 300-bead fixture', async ({
147		page,
148		request
149	}) => {
150		const ids = await getFixtureIds(request);
151		await mockSmokeGraphQL(page, 300, ids);
152	
153		const start = Date.now();
154		await page.goto(`/nodes/${ids.nodeId}/beads`);
155		await expect(page.getByRole('heading', { name: 'Beads' })).toBeVisible({ timeout: 2000 });
156		await expect(page.getByText('Smoke fixture bead 0')).toBeVisible({ timeout: 2000 });
157		const elapsed = Date.now() - start;
158		expect(elapsed, `cross-project /beads interactive in ${elapsed}ms (ceiling 2000ms)`).toBeLessThan(
159			2000
160		);
161	});
